export async function getDashboardStats() {
  if (useMock()) {
    const items = [..._items];
    const catCounts = {};
    items.forEach(i => { catCounts[i.category_id] = (catCounts[i.category_id] || 0) + 1; });
    const velCounts = { fast: 0, medium: 0, slow: 0 };
    items.forEach(i => { velCounts[i.velocity_status] = (velCounts[i.velocity_status] || 0) + 1; });

    return {
      total_items:        items.length,
      total_categories:   _categories.length,
      total_locations:    _locations.length,
      total_suppliers:    _suppliers.length,
      total_stock_value:  items.reduce((s, i) => s + i.stock_count * (i.unit_price ?? i.price ?? 0), 0),
      low_stock_count:    items.filter(i => i.stock_count < (i.min_stock ?? 10)).length,
      out_of_stock_count: items.filter(i => i.stock_count === 0).length,
      active_alerts:      _alerts.filter(a => !a.is_acknowledged).length,
      transactions_today: _transactions.filter(t => t.created_at?.startsWith(new Date().toISOString().slice(0, 10))).length,
      items_by_velocity:  velCounts,
      items_by_category:  _categories.map(c => ({
        name:  c.name,
        count: items.filter(i => i.category_id === c.id).length,
        value: items.filter(i => i.category_id === c.id).reduce((s, i) => s + i.stock_count * (i.unit_price ?? i.price ?? 0), 0),
      })),
      // Legacy fields kept for Dashboard page compatibility
      totalItems:     items.length,
      totalQuantity:  items.reduce((s, i) => s + i.stock_count, 0),
      lowStockCount:  items.filter(i => i.stock_count < (i.min_stock ?? 10)).length,
      totalLocations: _locations.length,
      totalValue:     items.reduce((s, i) => s + i.stock_count * (i.unit_price ?? i.price ?? 0), 0),
      recentItems:    [...items].sort((a, b) => b.id - a.id).slice(0, 5),
      lowStockItems:  items.filter(i => i.stock_count < (i.min_stock ?? 10)).slice(0, 5),
    };
  }
  try {
    const { data, error } = await sb().rpc('get_dashboard_stats');
    if (!error && data) {
      // Merge RPC result with legacy field names for Dashboard page
      return {
        ...data,
        totalItems:     data.total_items,
        totalQuantity:  data.total_stock_value,
        lowStockCount:  data.low_stock_count,
        totalLocations: data.total_locations,
        totalValue:     data.total_stock_value,
        recentItems:    [],
        lowStockItems:  [],
      };
    }
  } catch {}
  // Fallback: compute from items table
  const { data: items } = await sb().from('v_items').select('*');
  const safeItems = items ?? [];
  return {
    total_items:        safeItems.length,
    totalItems:         safeItems.length,
    totalQuantity:      safeItems.reduce((s, i) => s + (i.stock_count ?? 0), 0),
    lowStockCount:      safeItems.filter(i => i.stock_count < (i.min_stock ?? 10)).length,
    low_stock_count:    safeItems.filter(i => i.stock_count < (i.min_stock ?? 10)).length,
    totalLocations:     0,
    total_stock_value:  safeItems.reduce((s, i) => s + (i.stock_count ?? 0) * (i.unit_price ?? 0), 0),
    totalValue:         safeItems.reduce((s, i) => s + (i.stock_count ?? 0) * (i.unit_price ?? 0), 0),
    active_alerts:      0,
    recentItems:        [...safeItems].sort((a, b) => b.id - a.id).slice(0, 5),
    lowStockItems:      safeItems.filter(i => i.stock_count < (i.min_stock ?? 10)).slice(0, 5),
    items_by_velocity:  { fast: 0, medium: 0, slow: 0 },
    items_by_category:  [],
  };
}

